import os
from tensorflow.python.saved_model import tag_constants
import tensorflow as tf
from google.cloud import storage

def fetch_latest_model():
    client = storage.Client()
    bucket_name = os.environ['BUCKET_NAME']
    model_prefix = os.environ['MODEL_PREFIX']

    blobs = client.list_blobs(bucket_name, prefix=model_prefix)

    latest_tag = max([int(blob.name.split('-')[-1].replace('.tar.gz', '')) for blob in blobs])
    model_path = f'gs://{bucket_name}/{model_prefix}-{latest_tag}.tar.gz'

    return model_path

def load_serving_model(model_dir):
    builder = tf.saved_model.builder.SavedModelBuilder(model_dir)
    with open(model_dir + '/saved_model.pb', 'rb') as f:
        graph_def = tf.GraphDef.FromTensorFlowFile(f)

    signature_constants = tf.saved_model.signature_constants.DEFAULT_SERVING_SIGNATURE_DEF_KEY

    builder.add_meta_graph_and_variables(
            sess=tf.Session(graph=graph_def),
            tag_map={signature_constants.SERVING_DEFAULT_INPUT_SIGNATURE_DEF_KEY: tf.saved_model.signature_def_utils.get_default_input_signature_def(),
                     signature_constants.SERVING_PREDICT_FUNCTION_NAME: tf.saved_model.signature_constants.DEFAULT_CLASSES[0]})
    builder.save()

def main():
    MODEL_PATH = os.environ['MODEL_PATH']

    if not tf.io.gfile.exists(MODEL_PATH):
        MODEL_PATH = fetch_latest_model()
        print(f"Latest model not found, fetching {MODEL_PATH}")

    load_serving_model(os.path.dirname(MODEL_PATH))

if __name__ == "__main__":
    main()